import React, { useState } from "react";
import { useAppointments, useDoctors } from "../hooks";
import Modal from "../components/Modal";
import BookAppointmentForm from "../components/BookAppointmentForm";
import Spinner from "../components/Spinner";
import Toast from "../components/Toast";
import { formatSlot } from "../utils/helpers";

const POLL_INTERVAL = 20000; // 20 seconds

export default function AppointmentsPage() {
  const { appointments, loading, error, cancelAppointment } = useAppointments(POLL_INTERVAL);
  const { doctors } = useDoctors();
  const [search, setSearch] = useState("");
  const [sortKey, setSortKey] = useState("slot");
  const [sortDir, setSortDir] = useState("asc");
  const [confirmId, setConfirmId] = useState(null);
  const [cancelLoading, setCancelLoading] = useState(false);
  const [bookOpen, setBookOpen] = useState(false);
  const [toast, setToast] = useState(null);

  const getDoctorName = (id) => doctors.find((d) => d.id === id)?.name || `Doctor #${id}`;

  const filtered = appointments.filter((a) => {
    const q = search.toLowerCase();
    return getDoctorName(a.doctor_id).toLowerCase().includes(q) ||
      a.patient_name.toLowerCase().includes(q);
  });

  const sorted = [...filtered].sort((a, b) => {
    let va, vb;
    if (sortKey === "doctor") {
      va = getDoctorName(a.doctor_id); vb = getDoctorName(b.doctor_id);
    } else if (sortKey === "patient") {
      va = a.patient_name; vb = b.patient_name;
    } else {
      va = a.slot; vb = b.slot;
    }
    if (va < vb) return sortDir === "asc" ? -1 : 1;
    if (va > vb) return sortDir === "asc" ? 1 : -1;
    return 0;
  });

  const handleSort = (key) => {
    if (sortKey === key) setSortDir((d) => d === "asc" ? "desc" : "asc");
    else { setSortKey(key); setSortDir("asc"); }
  };

  const handleCancel = async () => {
    setCancelLoading(true);
    try {
      await cancelAppointment(confirmId);
      setConfirmId(null);
      setToast({ message: "Appointment cancelled.", type: "info" });
    } catch (e) {
      setToast({ message: e.response?.data?.detail || "Cancellation failed.", type: "error" });
    } finally {
      setCancelLoading(false);
    }
  };

  const thStyle = (key) => ({
    padding: "12px 16px",
    fontFamily: "'DM Mono', monospace",
    fontSize: 11,
    letterSpacing: 1,
    textTransform: "uppercase",
    color: sortKey === key ? "#00bcd4" : "#546e7a",
    textAlign: "left",
    cursor: "pointer",
    background: "none",
    border: "none",
    userSelect: "none",
    whiteSpace: "nowrap",
  });

  return (
    <div>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: 32 }}>
        <div>
          <h1 style={{ fontFamily: "'Syne', sans-serif", fontSize: 32, color: "#e0f7fa", margin: 0 }}>Appointments</h1>
          <p style={{ color: "#546e7a", fontFamily: "'DM Mono', monospace", marginTop: 6 }}>
            Auto-refreshes every 20s · {appointments.length} total
          </p>
        </div>
        <button
          onClick={() => setBookOpen(true)}
          style={{
            background: "linear-gradient(135deg, #006080, #00bcd4)",
            border: "none", borderRadius: 9, padding: "11px 22px",
            color: "#fff", fontFamily: "'Syne', sans-serif", fontWeight: 700,
            fontSize: 14, cursor: "pointer",
          }}
        >
          + Book Appointment
        </button>
      </div>

      {/* Filters */}
      <input
        style={{
          background: "#020810", border: "1px solid #0d3a5c", borderRadius: 8,
          padding: "10px 14px", color: "#cfd8dc", fontFamily: "'DM Mono', monospace",
          fontSize: 14, outline: "none", width: 320, marginBottom: 24, boxSizing: "border-box",
        }}
        placeholder="Filter by doctor or patient name…"
        value={search}
        onChange={(e) => setSearch(e.target.value)}
      />

      {loading && <div style={{ textAlign: "center", padding: 40 }}><Spinner /></div>}
      {error && <p style={{ color: "#ff4d6d", fontFamily: "'DM Mono', monospace" }}>{error}</p>}

      {!loading && (
        <div style={{ background: "#060f1a", border: "1px solid #0d3a5c", borderRadius: 14, overflow: "hidden" }}>
          <table style={{ width: "100%", borderCollapse: "collapse" }}>
            <thead>
              <tr style={{ borderBottom: "1px solid #0d3a5c" }}>
                <th style={thStyle("doctor")} onClick={() => handleSort("doctor")}>
                  Doctor {sortKey === "doctor" ? (sortDir === "asc" ? "↑" : "↓") : ""}
                </th>
                <th style={thStyle("patient")} onClick={() => handleSort("patient")}>
                  Patient {sortKey === "patient" ? (sortDir === "asc" ? "↑" : "↓") : ""}
                </th>
                <th style={thStyle("slot")} onClick={() => handleSort("slot")}>
                  Slot {sortKey === "slot" ? (sortDir === "asc" ? "↑" : "↓") : ""}
                </th>
                <th style={{ ...thStyle(""), cursor: "default" }}>Action</th>
              </tr>
            </thead>
            <tbody>
              {sorted.length === 0 ? (
                <tr>
                  <td colSpan={4} style={{ textAlign: "center", padding: 40, color: "#263238", fontFamily: "'DM Mono', monospace" }}>
                    No appointments found.
                  </td>
                </tr>
              ) : (
                sorted.map((a, i) => (
                  <tr key={a.id} style={{
                    borderBottom: i < sorted.length - 1 ? "1px solid #0d2e48" : "none",
                    transition: "background 0.15s",
                  }}
                    onMouseEnter={(e) => e.currentTarget.style.background = "#020810"}
                    onMouseLeave={(e) => e.currentTarget.style.background = ""}
                  >
                    <td style={{ padding: "14px 16px", color: "#00bcd4", fontFamily: "'DM Mono', monospace", fontSize: 13 }}>
                      {getDoctorName(a.doctor_id)}
                    </td>
                    <td style={{ padding: "14px 16px", color: "#90a4ae", fontFamily: "'DM Mono', monospace", fontSize: 13 }}>
                      {a.patient_name}
                    </td>
                    <td style={{ padding: "14px 16px", color: "#78909c", fontFamily: "'DM Mono', monospace", fontSize: 12 }}>
                      {formatSlot(a.slot)}
                    </td>
                    <td style={{ padding: "14px 16px" }}>
                      <button
                        onClick={() => setConfirmId(a.id)}
                        style={{
                          background: "none", border: "1px solid #ff4d6d33",
                          borderRadius: 6, padding: "5px 14px",
                          color: "#ff4d6d", fontFamily: "'DM Mono', monospace", fontSize: 12,
                          cursor: "pointer",
                        }}
                      >
                        Cancel
                      </button>
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
      )}

      {/* Confirm Cancel Modal */}
      <Modal isOpen={!!confirmId} onClose={() => setConfirmId(null)} title="Cancel Appointment" maxWidth={420}>
        <p style={{ color: "#90a4ae", fontFamily: "'DM Mono', monospace", fontSize: 14, marginBottom: 24 }}>
          Are you sure you want to cancel this appointment? This action cannot be undone.
        </p>
        <div style={{ display: "flex", gap: 12 }}>
          <button
            onClick={() => setConfirmId(null)}
            style={{
              flex: 1, padding: "11px 0", background: "none",
              border: "1px solid #0d3a5c", borderRadius: 9,
              color: "#78909c", fontFamily: "'Syne', sans-serif", fontSize: 14,
              cursor: "pointer",
            }}
          >
            Keep it
          </button>
          <button
            onClick={handleCancel}
            disabled={cancelLoading}
            style={{
              flex: 1, padding: "11px 0",
              background: cancelLoading ? "#2e0d0d" : "#ff1744",
              border: "none", borderRadius: 9,
              color: "#fff", fontFamily: "'Syne', sans-serif", fontWeight: 700, fontSize: 14,
              cursor: cancelLoading ? "not-allowed" : "pointer",
              display: "flex", alignItems: "center", justifyContent: "center", gap: 8,
            }}
          >
            {cancelLoading ? <><Spinner size={16} color="#fff" /> Cancelling…</> : "Yes, Cancel"}
          </button>
        </div>
      </Modal>

      {/* Book Modal */}
      <Modal isOpen={bookOpen} onClose={() => setBookOpen(false)} title="Book Appointment">
        <BookAppointmentForm
          onSuccess={() => {
            setBookOpen(false);
            setToast({ message: "Appointment booked!", type: "success" });
          }}
        />
      </Modal>

      {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}
    </div>
  );
}
